/*!
 * gameMechanic.js — Compiled output of Card/GameMechanic/*.ts
 *
 * DO NOT EDIT THIS FILE BY HAND.
 *   To regenerate after editing .ts sources:
 *       npm run build:mechanic
 *
 * Layout: one big IIFE that defines `GM` and registers all primitives,
 * prophecies, passives, and card definitions. Final line exposes `GM`
 * onto globalThis so the browser test harness can read it.
 */
var GM;
(function (GM) {
  "use strict";

  /* ====================================================================== */
  /*  Registry.ts                                                           */
  /* ====================================================================== */
  GM.CardEffects = {};
  GM.ProphecyResolvers = {};
  GM.TurnStartEffects = {};

  /* ====================================================================== */
  /*  Primitives                                                            */
  /* ====================================================================== */

  // --- Primitives/SelfDamage.ts ---
  GM.selfDamage = function (player, amount) {
    if (!Number.isFinite(amount) || amount <= 0) return 0;
    var before = player.hp;
    var actual = Math.min(Math.floor(amount), before);
    player.hp = before - actual;
    return actual;
  };

  // --- Primitives/SelfHealing.ts ---
  GM.selfHealing = function (player, spec) {
    var requested;
    if ("flat" in spec) {
      if (!Number.isFinite(spec.flat) || spec.flat <= 0) return 0;
      requested = Math.floor(spec.flat);
    } else {
      if (!Number.isFinite(spec.pctOfMax) || spec.pctOfMax <= 0) return 0;
      // BASE = maxHp (NEVER currentHp).
      requested = Math.max(1, Math.floor(player.maxHp * spec.pctOfMax));
    }
    var missing = player.maxHp - player.hp;
    if (missing <= 0) return 0;
    var actual = Math.min(requested, missing);
    player.hp += actual;
    return actual;
  };

  // --- Primitives/ManaGain.ts ---
  GM.manaGain = function (player, amount) {
    if (!Number.isFinite(amount) || amount <= 0) return 0;
    var safe = Math.floor(amount);
    player.mana += safe;
    return safe;
  };

  // --- Primitives/PlaceTree.ts ---
  GM.placeTree = function (player) {
    player.trees += 1;
  };

  // --- Primitives/AddProphecy.ts ---
  GM.addProphecy = function (target, owner, mode) {
    target.incomingProphecies.push({ owner: owner, mode: mode });
  };

  /* ====================================================================== */
  /*  Prophecies                                                            */
  /* ====================================================================== */

  // --- Prophecies/Destruction.ts ---
  GM.ProphecyResolvers["destruction"] = function (ctx) {
    var target = ctx.target, owner = ctx.owner, state = ctx.state, log = ctx.log;
    if (state.cardsThisTurn >= 1) {
      var healed = GM.selfHealing(owner, { flat: 8 });
      log(
        "effect",
        "Tiên tri hủy diệt ✓ — " + target.name + " đánh " + state.cardsThisTurn + " bài " +
        "→ " + owner.name + " +" + healed + " HP (" + owner.hp + "/" + owner.maxHp + ")"
      );
    } else {
      log("proph", "Tiên tri hủy diệt ✗ — " + target.name + " không đánh bài nào");
    }
  };

  // --- Prophecies/Peace.ts ---
  GM.ProphecyResolvers["peace"] = function (ctx) {
    var target = ctx.target, owner = ctx.owner, state = ctx.state, log = ctx.log;
    if (state.cardsThisTurn === 0) {
      var gained = GM.manaGain(owner, 8);
      log(
        "effect",
        "Tiên tri hòa bình ✓ — " + target.name + " không đánh bài " +
        "→ " + owner.name + " +" + gained + " mana"
      );
    } else {
      log(
        "proph",
        "Tiên tri hòa bình ✗ — " + target.name + " đã đánh " + state.cardsThisTurn + " bài"
      );
    }
  };

  /* ====================================================================== */
  /*  Passives                                                              */
  /* ====================================================================== */

  // --- Passives/TreeHeal.ts ---
  var TREE_HEAL_PCT = 0.05;
  GM.TurnStartEffects["tree"] = function (ctx) {
    var owner = ctx.owner, log = ctx.log;
    if (owner.trees <= 0) return;
    var perTree = Math.max(1, Math.floor(owner.maxHp * TREE_HEAL_PCT));
    var requested = perTree * owner.trees;
    var actual = GM.selfHealing(owner, { flat: requested });
    if (actual > 0) {
      log(
        "effect",
        "🌳 " + owner.trees + " cây của " + owner.name + " hồi " + actual + " HP " +
        "(" + perTree + "/cây) → " + owner.hp + "/" + owner.maxHp
      );
    }
  };

  /* ====================================================================== */
  /*  Cards — compose primitives                                            */
  /* ====================================================================== */

  // --- Cards/TienTriHuyDiet.ts ---
  GM.CardEffects["Tiên tri hủy diệt"] = {
    onPlay: function (ctx) {
      var me  = ctx.players[ctx.selfIdx];
      var opp = ctx.players[ctx.oppIdx];
      GM.addProphecy(opp, ctx.selfIdx, "destruction");
      ctx.log(
        "proph",
        "   ↪ Lời tiên tri: nếu " + opp.name + " đánh ≥1 bài lượt sau " +
        "→ " + me.name + " hồi 8 HP"
      );
    },
  };

  // --- Cards/TienTriHoaBinh.ts ---
  GM.CardEffects["Tiên tri hòa bình"] = {
    onPlay: function (ctx) {
      var me  = ctx.players[ctx.selfIdx];
      var opp = ctx.players[ctx.oppIdx];
      GM.addProphecy(opp, ctx.selfIdx, "peace");
      ctx.log(
        "proph",
        "   ↪ Lời tiên tri: nếu " + opp.name + " KHÔNG đánh bài lượt sau " +
        "→ " + me.name + " hồi 8 mana"
      );
    },
  };

  // --- Cards/CayCoThu.ts ---
  GM.CardEffects["Cây cổ thụ"] = {
    onPlay: function (ctx) {
      var me = ctx.players[ctx.selfIdx];
      GM.placeTree(me);
      ctx.log(
        "effect",
        "   ↪ Đặt 1 🌳 vào ô linh vật của " + me.name + " (tổng " + me.trees + " cây)"
      );
    },
  };
})(GM || (GM = {}));

/* ====================================================================== */
/*  Init.ts — expose to browser                                           */
/* ====================================================================== */
(function () {
  var g = typeof globalThis !== "undefined" ? globalThis : this;
  g.GM = GM;
})();
